(()=>{"use strict";!function(){const e=document.querySelectorAll('.toggle input[type="checkbox"], .toggle input[type="radio"]');e&&e.forEach((e=>{let t=e.parentElement;e.disabled&&t.classList.add("toggle--disabled"),t.setAttribute("tabindex","-1"),e.addEventListener("click",(()=>{t.classList.add("toggle--ripple"),setTimeout((()=>t.classList.remove("toggle--ripple")),325)}))}))}()})();